async function loadSiteConfig(){try{const snap=await getDoc(doc(db,'config','site'));if(snap.exists()){const d=snap.data();if(d.siteName)document.getElementById('cfgSiteName').value=d.siteName;if(d.slogan)document.getElementById('cfgSlogan').value=d.slogan;if(d.announcement)document.getElementById('cfgAnnouncement').value=d.announcement;if(d.announcementType)document.getElementById('cfgAnnouncementType').value=d.announcementType;if(d.shopDiscountEnd){const dt=new Date(d.shopDiscountEnd);const pad=n=>String(n).padStart(2,'0');const local=`${dt.getFullYear()}-${pad(dt.getMonth()+1)}-${pad(dt.getDate())}T${pad(dt.getHours())}:${pad(dt.getMinutes())}`;document.getElementById('cfgShopDiscountEnd').value=local;}}}catch(e){}}
async function saveSiteConfig(){const shopDiscountRaw=document.getElementById('cfgShopDiscountEnd')?.value;const cfg={siteName:document.getElementById('cfgSiteName').value.trim(),slogan:document.getElementById('cfgSlogan').value.trim(),announcement:document.getElementById('cfgAnnouncement').value.trim(),announcementType:document.getElementById('cfgAnnouncementType').value,shopDiscountEnd:shopDiscountRaw?new Date(shopDiscountRaw).toISOString():'',};await setDoc(doc(db,'config','site'),cfg,{merge:true});toast('Configuración guardada ✅','ok');if(cfg.announcement)showAnnouncement(cfg);}
let _shopCountdownTimer=null;function startShopCountdown(isoEnd){const banner=document.getElementById('shopDiscountBanner');const labelEl=document.getElementById('shopDiscountEndLabel');if(!banner)return;if(_shopCountdownTimer)clearInterval(_shopCountdownTimer);if(!isoEnd){banner.style.display='none';return;}
const end=new Date(isoEnd);if(isNaN(end.getTime())){banner.style.display='none';return;}
if(labelEl){const opts={day:'2-digit',month:'long',year:'numeric',hour:'2-digit',minute:'2-digit'};labelEl.textContent='📅 Vence: '+end.toLocaleString('es-AR',opts);}
const totalDuration=30*24*3600000;function tick(){const now=new Date();const diff=end-now;const dEl=document.getElementById('_cdDays');const hEl=document.getElementById('_cdHours');const mEl=document.getElementById('_cdMins');const sEl=document.getElementById('_cdSecs');const bar=document.getElementById('_cdProgressBar');const pad=n=>String(Math.floor(n)).padStart(2,'0');if(diff<=0){if(dEl)dEl.textContent='00';if(hEl)hEl.textContent='00';if(mEl)mEl.textContent='00';if(sEl)sEl.textContent='00';if(bar)bar.style.width='0%';clearInterval(_shopCountdownTimer);banner.style.display='none';return;}
const d=Math.floor(diff/86400000);const h=Math.floor((diff%86400000)/3600000);const m=Math.floor((diff%3600000)/60000);const s=Math.floor((diff%60000)/1000);if(dEl)dEl.textContent=pad(d);if(hEl)hEl.textContent=pad(h);if(mEl)mEl.textContent=pad(m);if(sEl)sEl.textContent=pad(s);if(bar){const pct=Math.min(100,Math.max(0,(diff/totalDuration)*100));bar.style.width=pct+'%';if(pct<15)bar.style.background='linear-gradient(90deg,#ff0000,#ff4500)';else if(pct<40)bar.style.background='linear-gradient(90deg,#ff8c00,#ff4500)';else bar.style.background='linear-gradient(90deg,#ffd700,#ff4500)';}
if(sEl){sEl.style.transition='transform .15s';sEl.style.transform='scale(1.2)';setTimeout(()=>{if(sEl)sEl.style.transform='scale(1)';},150);}}
banner.style.display='block';tick();_shopCountdownTimer=setInterval(tick,1000);}
window.startShopCountdown=startShopCountdown;function loadShopDiscount(){getDoc(doc(db,'config','site')).then(snap=>{if(snap.exists()&&snap.data().shopDiscountEnd){startShopCountdown(snap.data().shopDiscountEnd);}}).catch(()=>{});}
