function filterSoporteBy(f){_soporteFilter=f;document.querySelectorAll('[id^="sfbtn-"]').forEach(b=>b.classList.remove('active'));const btn=document.getElementById('sfbtn-'+f);if(btn)btn.classList.add('active');renderSoporteTickets();}
