function _startVerifParticlesEl(canvas,container){const W=container.offsetWidth||800,H=container.offsetHeight||220;canvas.width=W;canvas.height=H;const ctx=canvas.getContext('2d');const particles=Array.from({length:30},()=>_makeParticle(W,H));function step(){ctx.clearRect(0,0,W,H);particles.forEach((p,i)=>{p.y-=p.vy;p.x+=p.vx;p.life-=1;if(p.life<=0){particles[i]=_makeParticle(W,H);return;}
const alpha=Math.min(1,p.life/40)*p.maxAlpha;ctx.save();ctx.globalAlpha=alpha;ctx.fillStyle=p.color;ctx.shadowColor=p.color;ctx.shadowBlur=8;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill();ctx.restore();});canvas._raf=requestAnimationFrame(step);}
if(canvas._raf)cancelAnimationFrame(canvas._raf);canvas._raf=requestAnimationFrame(step);}
async function sendFriendRequestFromProfile(uid,nick){const btn=document.getElementById('btnAddFriend_'+uid);if(btn){btn.disabled=true;btn.textContent='Enviando...';}
await sendFriendRequest(uid,nick);}
async function sendFriendRequest(uid,nick){if(!window.CU){toast('Inicia sesión primero','err');return;}
try{const snap=await getDoc(doc(db,'users',uid));if(!snap.exists())return;if(isAdminUser(snap.data())){toast('No podés agregar a este usuario','err');return;}
const notifs=snap.data().notifs||[];const alreadySent=notifs.some(n=>n.type==='friendRequest'&&n.fromId===window.CU.id);if(alreadySent){toast('Ya enviaste una solicitud a este usuario','inf');return;}
const notif={text:`👥 ${window.CU.nick} quiere ser tu amigo`,time:Date.now(),read:false,type:'friendRequest',fromId:window.CU.id,fromNick:window.CU.nick,fromAv:window.CU.av||''};await updateDoc(doc(db,'users',uid),{notifs:arrayUnion(notif)});_trimNotifs(uid);toast(`Solicitud enviada a ${nick} 👥`,'ok');cm('mUserProfile');}catch(e){toast('Error al enviar solicitud','err');}}
async function acceptFriendRequest(fromId,fromNick,notifIndex){addXP(5,'nuevo amigo');if(!window.CU){toast('Iniciá sesión primero','err');return;}
try{const[mySnap,theirSnap]=await Promise.all([getDoc(doc(db,'users',window.CU.id)),getDoc(doc(db,'users',fromId))]);if(!mySnap.exists()||!theirSnap.exists()){toast('Usuario no encontrado','err');return;}
const myFriends=mySnap.data().friends||[];const theirFriends=theirSnap.data().friends||[];const promises=[];if(!myFriends.includes(fromId))
promises.push(updateDoc(doc(db,'users',window.CU.id),{friends:[...myFriends,fromId]}));if(!theirFriends.includes(window.CU.id))
promises.push(updateDoc(doc(db,'users',fromId),{friends:[...theirFriends,window.CU.id]}));await Promise.all(promises);window.CU.friends=window.CU.friends||[];if(!window.CU.friends.includes(fromId))window.CU.friends.push(fromId);sendNotifToUser(fromId,`✅ ${window.CU.nick} aceptó tu solicitud de amistad`);const idx=_notifs.findIndex(n=>n.type==='friendRequest'&&n.fromId===fromId);if(idx!==-1)_notifs.splice(idx,1);else if(notifIndex>=0&&notifIndex<_notifs.length)_notifs.splice(notifIndex,1);try{const freshSnap=await getDoc(doc(db,'users',window.CU.id));const freshNotifs=freshSnap.exists()?(freshSnap.data().notifs||[]):_notifs;const updatedNotifs=freshNotifs.filter(n=>!(n.type==='friendRequest'&&n.fromId===fromId));await updateDoc(doc(db,'users',window.CU.id),{notifs:updatedNotifs.slice(0,50)});}catch(e){await updateDoc(doc(db,'users',window.CU.id),{notifs:_notifs.slice(0,50)}).catch(()=>{});}
renderNotifs();updateNotifBadge();await loadRealFriends();renderProfile();renderFriendSpotsInHome();toast(`¡Ahora sos amigo de ${fromNick}! 🎣`,'ok');}catch(e){console.error('acceptFriendRequest error:',e);toast('Error al aceptar: '+e.message,'err');}}
async function rejectFriendRequest(notifIndex,fromId){if(!window.CU)return;try{let toRemove=null;if(fromId){const idx=_notifs.findIndex(n=>n.type==='friendRequest'&&n.fromId===fromId);if(idx!==-1){toRemove=_notifs[idx];_notifs.splice(idx,1);}}else{toRemove=notifIndex>=0&&notifIndex<_notifs.length?_notifs[notifIndex]:null;if(notifIndex>=0&&notifIndex<_notifs.length)_notifs.splice(notifIndex,1);}
if(toRemove){await updateDoc(doc(db,'users',window.CU.id),{notifs:arrayRemove(toRemove)});}
else{await updateDoc(doc(db,'users',window.CU.id),{notifs:_notifs.slice(0,50)});}
renderNotifs();toast('Solicitud rechazada','inf');}catch(e){toast('Error','err');}}
async function dismissFriendRequest(notifIndex){if(!window.CU)return;const toRemove=notifIndex>=0&&notifIndex<_notifs.length?_notifs[notifIndex]:null;if(notifIndex>=0&&notifIndex<_notifs.length)_notifs.splice(notifIndex,1);try{if(toRemove){await updateDoc(doc(db,'users',window.CU.id),{notifs:arrayRemove(toRemove)});}
else{await updateDoc(doc(db,'users',window.CU.id),{notifs:_notifs.slice(0,50)});}}catch(e){}
renderNotifs();}
function togglePostMenu(pid,e,ownerId){if(e)e.stopPropagation();document.querySelectorAll('[id^="pmenu_"]').forEach(m=>{if(m.id!=='pmenu_'+pid)m.style.display='none';});const menu=document.getElementById('pmenu_'+pid);if(!menu)return;const menuOwner=(ownerId||menu.dataset.owner||'').trim();const myId=(window.CU?.id||'').trim();const isAdmin=!!(window.CU?.admin||window.CU?.nick==='ruizgustavo12'||window.CU?.role==='admin'||window.CU?.email==='synxyes@gmail.com');const isOwner=!!(myId&&(menuOwner===myId));menu.querySelectorAll('[data-owner-only]').forEach(b=>{b.style.display=(isOwner||isAdmin)?'flex':'none';});menu.querySelectorAll('[data-other-only]').forEach(b=>{b.style.display=(!isOwner&&myId)?'flex':'none';});menu.querySelectorAll('.admin-only-feed-del').forEach(b=>{b.style.display=isAdmin?'flex':'none';});if(!myId){menu.querySelectorAll('[data-owner-only],[data-other-only],.admin-only-feed-del').forEach(b=>b.style.display='none');}
const visibleBtns=[...menu.querySelectorAll('button')].filter(b=>b.style.display!=='none');if(!visibleBtns.length){menu.style.display='none';return;}
const isOpen=menu.style.display==='block';menu.style.display=isOpen?'none':'block';if(!isOpen){setTimeout(()=>{document.addEventListener('click',function closeMenu(ev){if(!menu.contains(ev.target)){menu.style.display='none';document.removeEventListener('click',closeMenu);}});},10);}}
