_voiceAudioCtx=new(window.AudioContext||window.webkitAudioContext)();const source=_voiceAudioCtx.createMediaStreamSource(_voiceStream);_voiceAnalyser=_voiceAudioCtx.createAnalyser();_voiceAnalyser.fftSize=64;source.connect(_voiceAnalyser);const mimeType=MediaRecorder.isTypeSupported('audio/webm;codecs=opus')?'audio/webm;codecs=opus':MediaRecorder.isTypeSupported('audio/webm')?'audio/webm':'audio/ogg';_audioChunks=[];_mediaRecorder=new MediaRecorder(_voiceStream,{mimeType});_mediaRecorder.ondataavailable=e=>{if(e.data.size>0)_audioChunks.push(e.data);};_mediaRecorder.start(100);const inputEl=document.getElementById('chatInput');const micBtn=document.getElementById('voiceMsgBtn');const sendBtn=document.getElementById('chatSendBtn');const bar=document.getElementById('voiceRecordingBar');if(inputEl)inputEl.style.display='none';if(micBtn)micBtn.style.display='none';if(sendBtn)sendBtn.style.display='none';if(bar){bar.style.display='flex';}
