function renderGifResults(gifs,grid,pickerId,targetId){if(!gifs||!gifs.length){grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:16px;color:var(--muted);font-size:.78rem;">Sin resultados</div>';return;}
grid.innerHTML=gifs.map(g=>{const url=g.images.fixed_height_small.url;const original=g.images.original.url;return`<div class="gif-item" onclick="sendGif('${original}','${pickerId}','${targetId}')"><img src="${url}" loading="lazy" alt="gif"></div>`;}).join('');}
function sendGif(gifUrl,pickerId,targetId){closeGifPicker(pickerId);if(targetId==='chatInput'){sendChatMsg(gifUrl);}else{submitCommentGif(gifUrl,targetId.replace('cinp_',''));}}
