function maskEmail(email){if(!email||!email.includes('@'))return'—';const[user,domain]=email.split('@');const[domName,...domExt]=domain.split('.');const maskUser=user.length<=2?user[0]+'*':user[0]+'*'.repeat(Math.min(user.length-2,4))+user[user.length-1];const maskDom=domName.length<=2?domName[0]+'*':domName[0]+'*'.repeat(Math.min(domName.length-1,2));return maskUser+'@'+maskDom+'.'+domExt.join('.');}
